#include "vl6180x.h"
#include <Wire.h>
#include <Adafruit_VL6180X.h>
static Adafruit_VL6180X vl;
static uint8_t _range=0;static float _lux=0;
static unsigned long _last=0;
void vl6180x_setup(){Wire.begin();if(!vl.begin()){Serial.println("[vl6180x] Fail!");return;}Serial.println("[vl6180x] OK");}
void vl6180x_loop(){if(millis()-_last<200)return;_last=millis();_range=vl.readRange();_lux=vl.readLux(VL6180X_ALS_GAIN_5);}
uint8_t vl6180x_get_range_mm(){return _range;}
float vl6180x_get_lux(){return _lux;}
